/* ============ CLARET & BRASS ============ */
/* Fonts: Source Serif 4 (display), Inter (body), IBM Plex Mono (labels) */

html,body,#root{font-family:'Inter',system-ui,-apple-system,sans-serif !important;color:#2B1116 !important;-webkit-font-smoothing:antialiased !important;text-rendering:optimizeLegibility !important}
body{background-color:#F6F1E7 !important}

/* Kill gradients for flat, premium fills */
.bg-gradient-to-br,.bg-gradient-to-r,.bg-gradient-to-b,.bg-gradient-to-t,.bg-gradient-to-tr{background-image:none !important}

/* ---- DISPLAY TYPE: Source Serif, legal gravitas ---- */
h1,h2,h3,h4,.text-2xl,.text-3xl,.text-4xl,.text-5xl{font-family:'Source Serif 4','Source Serif Pro',Georgia,serif !important;font-weight:600 !important;letter-spacing:-0.01em !important;color:#3D1019 !important}
h1,.text-4xl,.text-5xl{font-weight:700 !important;letter-spacing:-0.02em !important}

/* ---- LABELS: IBM Plex Mono, brass, tracked ---- */
.uppercase{font-family:'IBM Plex Mono',ui-monospace,monospace !important;letter-spacing:0.14em !important;font-weight:600 !important;font-size:0.68rem !important;text-transform:uppercase !important}

/* ---- GREY TEXT: crisp, no wash-out ---- */
.text-gray-900{color:#2B1116 !important}
.text-gray-800{color:#3D1019 !important}
.text-gray-700{color:#4A2228 !important}
.text-gray-600{color:#5C3A40 !important}
.text-gray-500{color:#7A5E27 !important}
.text-gray-400{color:#9A7B3F !important}

/* ---- SURFACES ---- */
[class*="border-gray-"]{border-color:#E6DCC8 !important}
.bg-gray-50,.bg-gray-100{background-color:#FBF7EF !important}
.bg-white{background-color:#FFFFFF !important}

.card{background:#FFFFFF !important;border:1px solid #E9E0CD !important;border-radius:14px !important;box-shadow:0 1px 2px rgba(61,16,25,0.04),0 8px 24px rgba(61,16,25,0.05) !important}
.rounded-md{border-radius:8px !important}
.rounded-lg{border-radius:10px !important}
.rounded-xl{border-radius:12px !important}
.rounded-2xl{border-radius:16px !important}
.shadow,.shadow-sm,.shadow-md{box-shadow:0 1px 2px rgba(61,16,25,0.05),0 4px 14px rgba(61,16,25,0.05) !important}
.shadow-lg,.shadow-xl,.shadow-2xl{box-shadow:0 6px 24px rgba(61,16,25,0.08),0 18px 50px rgba(61,16,25,0.08) !important}

input,select,textarea{font-family:'Inter',sans-serif !important;color:#2B1116 !important}

/* ---- DASHBOARD DEEP ---- */
.card .text-2xl,.card .text-3xl{font-family:'Source Serif 4','Source Serif Pro',Georgia,serif !important;font-size:2rem !important;font-weight:700 !important;letter-spacing:-0.02em !important;color:#3D1019 !important}
.card .text-sm.font-medium,.card .text-xs{font-family:'IBM Plex Mono',monospace !important;letter-spacing:0.1em !important;text-transform:uppercase !important;color:#7A5E27 !important}
.card h2,.card h3{font-family:'Source Serif 4','Source Serif Pro',Georgia,serif !important;color:#3D1019 !important}

/* ---- TOP BAR ---- */
header{background:#FFFFFF !important;border-bottom:1px solid #E6DCC8 !important;box-shadow:0 1px 0 rgba(61,16,25,0.03) !important}
header h2{font-family:'Source Serif 4','Source Serif Pro',Georgia,serif !important;color:#3D1019 !important;font-weight:600 !important}
header button{color:#5C3A40 !important}

/* ============================================================ */
/* #1 SIDEBAR REDESIGN — LIGHT IVORY RAIL, CRISP CLARET TYPE     */
