/* Light panel + hairline + brass accent edge */
#root .fixed.inset-y-0.left-0[class*="bg-[#011E41]"]{background:#FBF8F1 !important;border-right:1px solid #E6DCC8 !important;box-shadow:1px 0 0 rgba(154,123,63,0.10) !important}

/* All rail text -> crisp dark claret */
#root .fixed.inset-y-0.left-0 [class*="text-white"]{color:#3D1019 !important}
#root .fixed.inset-y-0.left-0 [class*="text-white/7"],#root .fixed.inset-y-0.left-0 [class*="text-white/6"],#root .fixed.inset-y-0.left-0 [class*="text-white/5"],#root .fixed.inset-y-0.left-0 [class*="text-white/4"],#root .fixed.inset-y-0.left-0 [class*="text-white/3"]{color:#6B4248 !important}

