/* ============ HARBOR — industrial-clean navy CRM ============ */

/* ---- Base typography + canvas ---- */
html,body,#root{font-family:'Inter',system-ui,-apple-system,sans-serif !important;color:#16304F !important;-webkit-font-smoothing:antialiased;text-rendering:optimizeLegibility}
body{background-color:#F4F6F8 !important}
.bg-gradient-to-br,.bg-gradient-to-r,.bg-gradient-to-b{background-image:none !important}

/* ---- Headings: condensed-confident, tight, navy ---- */
h1,h2,h3,h4,.text-2xl,.text-3xl,.text-4xl,.text-5xl{font-family:'Inter','sans-serif' !important;font-weight:700 !important;letter-spacing:-0.018em !important;color:#16304F !important}
.text-4xl,.text-5xl{letter-spacing:-0.028em !important;font-weight:800 !important}

/* ---- Uppercase labels: industrial, spaced, strong ---- */
.uppercase{font-family:'Inter','sans-serif' !important;letter-spacing:0.13em !important;font-weight:700 !important;font-size:0.68rem !important}

/* ---- Surfaces / cards ---- */
.card{background:#FFFFFF !important;border:1px solid #E4E8EC !important;border-radius:12px !important;box-shadow:0 1px 2px rgba(16,38,64,0.05),0 1px 3px rgba(16,38,64,0.04) !important}
.rounded-md{border-radius:8px !important}
.rounded-lg{border-radius:10px !important}
.rounded-xl{border-radius:12px !important}
.rounded-2xl{border-radius:14px !important}
.shadow,.shadow-sm,.shadow-md{box-shadow:0 1px 2px rgba(16,38,64,0.05),0 1px 3px rgba(16,38,64,0.04) !important}
.shadow-lg,.shadow-xl,.shadow-2xl{box-shadow:0 6px 18px rgba(16,38,64,0.10),0 2px 6px rgba(16,38,64,0.06) !important}

/* ---- Greys → cool, crisp, never washed-out ---- */
[class*="border-gray-"]{border-color:#E4E8EC !important}
.bg-gray-50{background-color:#F4F6F8 !important}
.bg-gray-100{background-color:#EDF1F4 !important}
.bg-white{background-color:#FFFFFF !important}
.text-gray-900{color:#16304F !important}
.text-gray-800{color:#1E3A5F !important}
.text-gray-700{color:#33465B !important}
.text-gray-600{color:#46586B !important}
.text-gray-500{color:#5A6B7D !important}
.text-gray-400{color:#7C8B9A !important}
input,select,textarea{font-family:'Inter','sans-serif' !important}

/* ============ #1 SIDEBAR — WHITE, SECTIONED, SHARP ============ */
/* Rail → light panel with hairline + no glass */
#root .fixed.inset-y-0.left-0[class*="bg-[#011E41]"]{background:#FFFFFF !important;border-right:1px solid #E4E8EC !important;box-shadow:0 0 0 1px rgba(16,38,64,0.02) !important;backdrop-filter:none !important}
#root .fixed.inset-y-0.left-0{background:#FFFFFF !important;backdrop-filter:none !important}

/* Rail text → crisp navy ink */
#root .fixed.inset-y-0.left-0 [class*="text-white"]{color:#16304F !important}
#root .fixed.inset-y-0.left-0 [class*="text-white/7"],#root .fixed.inset-y-0.left-0 [class*="text-white/6"],#root .fixed.inset-y-0.left-0 [class*="text-white/5"],#root .fixed.inset-y-0.left-0 [class*="text-white/4"],#root .fixed.inset-y-0.left-0 [class*="text-white/3"]{color:#4A5A6E !important}

/* Section headers (WORK / INTELLIGENCE / ...) → real headers + divider */
#root .fixed.inset-y-0.left-0 [class*="uppercase"]{font-family:'Inter','sans-serif' !important;letter-spacing:0.14em !important;font-size:0.66rem !important;font-weight:700 !important;color:#B26F12 !important;margin-top:16px !important;padding-top:14px !important;border-top:1px solid #E8ECF0 !important}

/* Nav items → sharp, weighted, padded */
#root .fixed.inset-y-0.left-0 a{font-family:'Inter','sans-serif' !important;font-size:0.875rem !important;font-weight:500 !important;letter-spacing:0.005em !important;border-radius:8px !important;margin:1px 8px !important;padding:8px 11px !important;color:#16304F !important;transition:background .12s ease,color .12s ease}
#root .fixed.inset-y-0.left-0 a:hover{background:#F1F4F7 !important;color:#1E3A5F !important}

/* Active item → amber left-bar pill, unmistakable */
#root .fixed.inset-y-0.left-0 a[class*="bg-white/15"]{background:#FCF3E3 !important;color:#16304F !important;font-weight:600 !important;border-left:3px solid #E0A23B !important;border-radius:0 8px 8px 0 !important;box-shadow:none !important}
#root .fixed.inset-y-0.left-0 a[class*="bg-white/15"] svg{color:#C9821C !important}

/* Icons → crisp muted navy-grey */
#root .fixed.inset-y-0.left-0 a svg{color:#5A6B7D !important;width:18px !important;height:18px !important}

/* Brand/avatar + footer hairlines */
#root .fixed.inset-y-0.left-0 [class*="rounded-full"]{background:#1E3A5F !important;color:#fff !important;border:none !important}
#root .fixed.inset-y-0.left-0 [class*="border-white"]{border-color:#E4E8EC !important}

